+                                    0);
+            CommT* reduced = reinterpret_cast<CommT*>(&tA[i]);
+            T* residual    = reinterpret_cast<T*>(&residual_atom);
+            T* x           = reinterpret_cast<T*>(&tA[i]);
+#pragma unroll
+            for(int e = 0; e < kElemsPerAtom; e++)
+            {
+                float sum = qr_to_float<CommT>(reduced[e]) + qr_to_float<T>(residual[e]);
+                x[e]      = qr_from_float<T>(sum);
+            }
+            buffer_store_dwordx4(tA[i],
+                                 residual_dst.descriptor,
+                                 tile_offset + i * kAtomStride * sizeof(int32x4_t),
+                                 0,
+                                 0);
+        }
+
+        BufferResource output_dst(output, N * sizeof(T));
+        BufferResource weight_src(const_cast<T*>(weight), hidden_dim * sizeof(T));
+
+        // Up to eight rows can span one or more complete 2048-element thread
+        // bands.  This is the hot path for transformer widths (including 4096
+        // and 8192): reduce all row sums concurrently, with only two barriers.
+        if(hidden_dim >= kElemsPerBand)
+        {
+            __shared__ float wave_sums[kMaxLargeRows][kWaves];
+            __shared__ float inv_rms[kMaxLargeRows];
+            float square_sum[kMaxLargeRows] = {};
+
+            uint32_t atoms_per_row = hidden_dim / kElemsPerBand;
+            uint32_t rows_per_tile = kElemsPerTile / hidden_dim;
+#pragma unroll
+            for(int i = 0; i < kAtoms; i++)
+            {
