+                T* x         = reinterpret_cast<T*>(&tA[i]);
+#pragma unroll
+                for(int e = 0; e < kElemsPerAtom; e++)
+                {
+                    float xf       = qr_to_float<T>(x[e]);
+                    square_sum[row] = fmaf(xf, xf, square_sum[row]);
+                }
+            }
+
+            for(uint32_t row = 0; row < rows_per_tile; row++)
+            {
+#pragma unroll
+                for(int offset = kWavefront / 2; offset > 0; offset >>= 1)
