+        // one band at a time in LDS; this keeps every legal tile divisor
+        // correct without burdening the transformer-width hot path.
+        else if(hidden_dim >= kElemsPerAtom)
+        {
+            __shared__ float thread_sums[kBlockSize];
+            __shared__ float inv_rms[kBlockSize];
+            uint32_t threads_per_row = hidden_dim / kElemsPerAtom;
+
+#pragma unroll
+            for(int i = 0; i < kAtoms; i++)
+            {
+                T* x = reinterpret_cast<T*>(&tA[i]);
+                float square_sum = 0.0f;
+#pragma unroll
+                for(int e = 0; e < kElemsPerAtom; e++)
+                {
+                    float xf   = qr_to_float<T>(x[e]);
+                    square_sum = fmaf(xf, xf, square_sum);
+                }
+                thread_sums[thread] = square_sum;
+                __syncthreads();
+
+                if((thread & (threads_per_row - 1)) == 0)
+                {
+                    float total = 0.0f;
+                    for(uint32_t t = 0; t < threads_per_row; t++)
+                    {
+                        total += thread_sums[thread + t];
+                    }
+                    inv_rms[thread / threads_per_row] =
+                        rsqrtf(total / static_cast<float>(hidden_dim) + eps);
+                }
+                __syncthreads();
+
+                float inv = inv_rms[thread / threads_per_row];
+                uint32_t weight_offset = (thread & (threads_per_row - 1)) * kElemsPerAtom;
+                int32x4_t weight_atom = buffer_load_dwordx4(
+                    weight_src.descriptor, weight_offset * sizeof(T), 0, 0);
+                T* w = reinterpret_cast<T*>(&weight_atom);
+#pragma unroll
+                for(int e = 0; e < kElemsPerAtom; e++)
+                {
+                    float normalized = (qr_to_float<T>(x[e]) * inv) * qr_to_float<T>(w[e]);
+                    x[e]             = qr_from_float<T>(normalized);
+                }
+                buffer_store_dwordx4(tA[i],
+                                     output_dst.descriptor,
+                                     tile_offset + i * kAtomStride * sizeof(int32x4_t),
+                                     0,
+                                     0);
+            }
+        }
+        else
+        {
+            // A 16-byte atom contains multiple complete rows when hidden_dim is
+            // 1, 2, or 4.  Those rows need no inter-thread reduction.
+#pragma unroll
+            for(int i = 0; i < kAtoms; i++)
+            {
+                T* x = reinterpret_cast<T*>(&tA[i]);
+                for(uint32_t first = 0; first < kElemsPerAtom; first += hidden_dim)
+                {
+                    float square_sum = 0.0f;
+                    for(uint32_t e = 0; e < hidden_dim; e++)
+                    {
+                        float xf   = qr_to_float<T>(x[first + e]);
+                        square_sum = fmaf(xf, xf, square_sum);
+                    }
+                    float inv = rsqrtf(square_sum / static_cast<float>(hidden_dim) + eps);
+                    for(uint32_t e = 0; e < hidden_dim; e++)
+                    {
+                        float normalized = (qr_to_float<T>(x[first + e]) * inv) *
+                                           qr_to_float<T>(weight[e]);
+                        x[first + e] = qr_from_float<T>(normalized);
+                    }
+                }
+                buffer_store_dwordx4(tA[i],
+                                     output_dst.descriptor,
+                                     tile_offset + i * kAtomStride * sizeof(int32x4_t),
+                                     0,
+                                     0);
+            }
         }
     }
 };
*** End Patch";
text(await tools.apply_patch(patch));

